%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%  LOCAL FUNCTIONS
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
function f = objective(xr, PB)
xh = decode(xr, PB);
f  = PB.core(xh);
end

function xh = decode(xr, PB)
if ~iscell(xr) || numel(xr) ~= 2
    error('schaffer2_k31_2D: xr must be a cell array with exactly 2 entries.');
end
xh = zeros(2,1);
tmp = check_C(xr{1}, PB.lb_C_work(1), PB.ub_C_work(1), 'x1');
xh(1) = map_C_to_orig(tmp, PB.lb_C_work(1), PB.ub_C_work(1), PB.lb_orig(1), PB.ub_orig(1));
xh(2) = check_K(xr{2}, PB.K2_labels, PB.K2_embed, 'x2');
end

function v = check_C(val, a, b, name)
if ~isnumeric(val) || ~isscalar(val) || ~isreal(val)
    error('schaffer2_k31_2D: %s must be a real scalar.', name);
end
if val < a || val > b
    error('schaffer2_k31_2D: %s=%g outside [%g,%g].', name, val, a, b);
end
v = double(val);
end

function xorig = map_C_to_orig(xwork, lbw, ubw, lbo, ubo)
if abs(ubw - lbw) <= 1e-14
    t = 0;
else
    t = (xwork - lbw) / (ubw - lbw);
end
t = max(0, min(1, t));
xorig = lbo + t * (ubo - lbo);
end

function v = check_D(val, grid, name)
if ~isnumeric(val) || ~isscalar(val) || ~isreal(val)
    error('schaffer2_k31_2D: %s must be a real scalar.', name);
end
grid = grid(:);
[dmin, idx] = min(abs(grid - val));
if dmin > 1e-10 * max(1, max(abs(grid)))
    error('schaffer2_k31_2D: %s=%g not in grid.', name, val);
end
v = grid(idx);
end

function v = check_K(label, labels, embed, name)
if isstring(label), label = char(label); end
if ~(ischar(label) && isrow(label))
    error('schaffer2_k31_2D: %s must be a char vector.', name);
end
idx = find(strcmp(label, labels), 1);
if isempty(idx)
    error('schaffer2_k31_2D: %s unknown label ''%s''.', name, label);
end
v = embed(idx);
end



% -------------------------------------------------------------------------
% Embedded original continuous problem (verbatim; only the top-level name is renamed)
% -------------------------------------------------------------------------
function [f] = schaffer2_orig(x)
%
% Purpose:
%
%    Function schaffer2 is the function described in
%    Montaz et al. (2005).
%
%    dim = 2
%    Minimum global value = 0
%    Global minima = [0 0]'
%    Local minima 
%    Search domain: -100 <= x <= 100 (Montaz et al. (2005))
%
% Input:  
%
%         x (point given by the optimizer).
%
% Output: 
%
%         f (function value at x).
%
% Written by A. L. Custodio and J. F. A. Madeira.
%
% Version June 2012.
%
%
f = (x(1)^2+x(2)^2)^0.25*(sin(50*(x(1)^2+x(2)^2)^0.1)^2+1);
end
%
% End of schaffer2.

